var e=[{id:`L2_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`큭…… 하아……`,JPN:`くっ……はあ……`,ENG:`*Pant*`,TWN:`咳……呼呼……`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`미나토님, 상처가 너무 심합니다!`,JPN:`湊様、傷が深すぎます！`,ENG:`Mr. Nayuka, you’re seriously injured!`,TWN:`南裕夏，你傷勢很嚴重！`},stage:{bg:`REEDS_FIELD_02`,slots:{L:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L7_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`괜찮아. 아직 활을 당기는 것쯤은…… 할 수 있어.`,JPN:`平気さ。まだ弓を引くことくらい……できる。`,ENG:`I’m okay. I can still pull the string.`,TWN:`沒關係，還可以拉弓… 我可以的。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SAYO_NPC_NANAHARA_NULL`,text:{KOREA:`그런 꼴로도 아직 저항할 수 있다니.`,JPN:`そんな様でもまだ抵抗するとは。`,ENG:`You still have a plenty of fight in you.`,TWN:`都傷成那樣還要抵抗嗎？`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`SAYO_NPC_NANAHARA_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SAYO_NPC_NANAHARA_NULL`,text:{KOREA:`아쉽지만, 목숨을 구걸하는 꼴은 못 보겠구나.`,JPN:`残念だが、命乞いをする姿は見られそうにないな。`,ENG:`I guess you won’t be begging for your life.`,TWN:`雖然很可惜，但你那副可憐樣我實在看不下去。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`SAYO_NPC_NANAHARA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`SAYO_NPC_NANAHARA_NULL`,text:{KOREA:`지금 당장 사이좋게 저승으로 보내주마.`,JPN:`今すぐにまとめてあの世に送ってやろう。`,ENG:`Well then, let me send you both to the hell.`,TWN:`我現在就立刻送你上路。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`SAYO_NPC_NANAHARA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`……치나츠.`,JPN:`……千夏。`,ENG:`... Chinatsu.`,TWN:`……千夏。`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`네?`,JPN:`はい？`,ENG:`Yes?`,TWN:`嗯？`},stage:{bg:`REEDS_FIELD_02`,slots:{L:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L19_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`엎드려!`,JPN:`伏せて！`,ENG:`Stay down!`,TWN:`趴下！`},stage:{bg:`REEDS_FIELD_02`,slots:{L:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L27_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`침식체들이…… 날아갔어?`,JPN:`侵食体が……飛ばされた？`,ENG:`The C.O.s flew away...`,TWN:`侵蝕體……消失了？`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`SAYO_NPC_NANAHARA_NULL`,text:{KOREA:`뭐냐? 방금 대체 무슨 일이 일어난 거지?`,JPN:`なんだ？　今何が起きた？`,ENG:`What? What just happened?`,TWN:`什麼？剛才到底發生什麼事？`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`SAYO_NPC_NANAHARA_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`저건……`,JPN:`あれは……`,ENG:`That’s...`,TWN:`那是……`},stage:{bg:`REEDS_FIELD_02`,slots:{L:null,C:{char_id:`CHINATSU_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`CHINATSU_NANA_NULL_NULL`,text:{KOREA:`카미이즈미?`,JPN:`上泉？`,ENG:`Kamiizumi?`,TWN:`上泉？`},stage:{bg:`SKY_NIGHT`,slots:{L:null,C:null,R:null}}},{id:`L35_1`,type:`dialog`,speaker:`ZENZIROU_NANA_NULL_NULL`,text:{KOREA:`한 발 적중! 맛이 어떠냐!`,JPN:`一発必中！　ざまあみろ！`,ENG:`Bullseye! How did you like that?`,TWN:`一發命中！ 滋味如何！`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L36_1`,type:`dialog`,speaker:`ZENZIROU_NANA_NULL_NULL`,text:{KOREA:`터뷸런스 동력을 다시 최대로 끌어올리자고!`,JPN:`タービュランス動力をもう一度最大まで引き上げようぜ！`,ENG:`Let’s maximize the power of Turbulence again!`,TWN:`再把不穩定氣流的動能升到最大！`},stage:{bg:`PROLOGUE_02`,slots:{L:null,C:{char_id:`ZENZIROU_NANA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}}];export{e as default};